const body = $input.first().json.body ?? $input.first().json;
const message = body.message ?? body.edited_message ?? null;
const callback = body.callback_query ?? null;

if (callback) {
  return [{ json: {
    update_type: 'callback',
    chat_id: String(callback.message.chat.id),
    callback_id: callback.id,
    callback_data: callback.data ?? '',
    message_id: callback.message.message_id,
    first_name: callback.from?.first_name ?? 'there',
    telegram_username: callback.from?.username ?? null
  }}];
}

if (message) {
  const text = message.text ?? '';
  const isCommand = text.startsWith('/');
  return [{ json: {
    update_type: isCommand ? 'command' : 'text',
    command: isCommand ? text.split(' ')[0].toLowerCase() : null,
    text: text,
    chat_id: String(message.chat.id),
    first_name: message.from?.first_name ?? 'there',
    telegram_username: message.from?.username ?? null
  }}];
}

return [{ json: { update_type: 'unknown', chat_id: null } }];

const user = $('Lookup User (/start)').first().json.records[0].fields;
const campaigns = $('Fetch Tech Campaigns').first().json.records ?? [];
const firstName = $('Parse Update').first().json.first_name;

let message;
let keyboard;

if (campaigns.length > 0) {
  const lines = campaigns.map(c => {
    const f = c.fields;
    const pct = f.goal_units > 0 ? Math.round((f.current_units / f.goal_units) * 100) : 0;
    return `• ${f.name ?? 'Campaign'}: ${f.current_units ?? 0}/${f.goal_units ?? 0} (${pct}%)`;
  }).join('\n');
  message = `Welcome back, ${firstName}! ✨\n\n📊 You have ${campaigns.length} active campaign${campaigns.length > 1 ? 's' : ''}:\n\n${lines}\n\nWhat would you like to do?`;
  keyboard = [[{
    text: '📊 Campaign Dashboard',
    callback_data: 'dashboard'
  }, {
    text: '🚀 Start New Campaign',
    callback_data: 'start_campaign'
  }], [{
    text: '🤖 Ask AI for Help',
    callback_data: 'ask_ai'
  }]];
} else {
  message = `Welcome back, ${firstName}! ✨\n\nYou don't have any active campaigns yet.\n\nStart one today!`;
  keyboard = [[{
    text: '🚀 Start First Campaign',
    callback_data: 'start_campaign'
  }, {
    text: '👀 Browse Products',
    callback_data: 'browse_products'
  }], [{
    text: '🤖 Ask AI',
    callback_data: 'ask_ai'
  }]];
}

return [{ json: { chat_id: $('Parse Update').first().json.chat_id, message, keyboard } }];

const text = $('Parse Update').first().json.text ?? '';
const username = text.trim().toLowerCase();
const valid = /^[a-z0-9]{3,32}$/.test(username);
const userRecord = $('Lookup User (text)').first().json.records[0];

return [{ json: {
  valid,
  username,
  chat_id: $('Parse Update').first().json.chat_id,
  user_record_id: userRecord?.id ?? null,
  error_reason: !valid
    ? (username.length < 3 ? 'too_short'
       : username.length > 32 ? 'too_long'
       : 'invalid_chars')
    : null
}}];

const data = $json.callback_data ?? '';
const isApprove = data.startsWith('approve_');
const isReject = data.startsWith('reject_');
const campaignId = (isApprove || isReject) ? data.split('_').slice(1).join('_') : null;

return [{ json: {
  ...($json),
  callback_action: isApprove ? 'approve' : isReject ? 'reject' : 'other',
  campaign_id: campaignId
}}];

const records = $input.first().json.records ?? [];
const chatId = $('Parse Update').first().json.chat_id;

if (records.length === 0) {
  return [{ json: { chat_id: chatId, message: 'No products available right now. Check back soon!', keyboard: [[{ text: '« Menu', callback_data: 'menu' }]] } }];
}

const lines = records.map((r, i) => {
  const f = r.fields;
  return `${i+1}. *${f.name ?? 'Product'}*\n   💰 Wholesale: $${f.wholesale_price ?? '?'}\n   💵 Suggested: $${f.suggested_retail ?? '?'}`;
}).join('\n\n');

const keyboard = records.map(r => [{
  text: `Select: ${r.fields.name ?? 'Product'}`,
  callback_data: `select_product_${r.id}`
}]);
keyboard.push([{ text: '« Menu', callback_data: 'menu' }]);

return [{ json: { chat_id: chatId, message: `🛍️ *Our Product Catalog:*\n\n${lines}`, keyboard } }];

const campaigns = $input.first().json.records ?? [];
const chatId = $('Parse Update').first().json.chat_id;
const firstName = $('Parse Update').first().json.first_name;

if (campaigns.length === 0) {
  return [{ json: { chat_id: chatId, message: `You don't have any campaigns yet.\n\nYour first campaign is just a few taps away!`, keyboard: [[{ text: '🚀 Start First Campaign', callback_data: 'start_campaign' }, { text: '« Menu', callback_data: 'menu' }]] } }];
}

const statusEmoji = { active: '🟢', pending_approval: '📝', successful: '🎉', completed: '✅', failed: '❌', cancelled: '⛔' };

const lines = campaigns.map(c => {
  const f = c.fields;
  const pct = f.goal_units > 0 ? Math.round((f.current_units / f.goal_units) * 100) : 0;
  const emoji = statusEmoji[f.status] ?? '📝';
  return `${emoji} *${f.name ?? 'Campaign'}*\n   Progress: ${f.current_units ?? 0}/${f.goal_units ?? 0} (${pct}%)`;
}).join('\n\n');

const keyboard = campaigns.filter(c => c.fields.status === 'active').map(c => [{
  text: `View: ${c.fields.name ?? 'Campaign'}`,
  callback_data: `view_campaign_${c.id}`
}]);
keyboard.push([{ text: '🚀 New Campaign', callback_data: 'start_campaign' }, { text: '« Menu', callback_data: 'menu' }]);

return [{ json: { chat_id: chatId, message: `📊 *Your Campaigns:*\n\n${lines}`, keyboard } }];

